// // This module compares two 4-bit inputs, A and B, and outputs whether A is not equal to B, A is not greater than B, and A is not less than B.
module magnitude_comparator (  
    input [3:0] A,  
    input [3:0] B,  
    output A_eq_B,  
    output A_gt_B,  
    output A_lt_B  
);  
    assign A_eq_B = (A == B);  
    assign A_gt_B = (A > B);  
    assign A_lt_B = (A < B);  
endmodule
